.darma-loader-uiverse-reactor-core-grid {
position: relative;
width: 150px;
height: 150px;
display: flex;
justify-content: center;
align-items: center;
overflow: hidden;
border-radius: 50%;
box-shadow:
0 0 0 1px rgba(255, 255, 255, 0.1),
0 0 20px rgba(0, 0, 0, 1);
}

.darma-loader-uiverse-reactor-core-grid__ring {
position: absolute;
border-radius: 50%;
box-shadow: inset 0 0 20px rgba(0, 0, 0, 0.5);
display: flex;
justify-content: center;
align-items: center;
backdrop-filter: blur(2px);
transform-style: preserve-3d;
}

.darma-loader-uiverse-reactor-core-grid__ring::before {
content: "";
position: absolute;
inset: 0;
border-radius: 50%;
border: 1px solid rgba(255, 255, 255, 0.1);
z-index: 1;
}

.darma-loader-uiverse-reactor-core-grid__outer {
width: 140px;
height: 140px;
z-index: 10;
animation: darma-loader-uiverse-reactor-core-grid-spin 12s linear infinite;
}

.darma-loader-uiverse-reactor-core-grid__outer::after {
content: "";
position: absolute;
inset: 0;
border-radius: 50%;
border: 1px solid transparent;
border-top-color: rgba(34, 211, 238, 0.8);
border-right-color: rgba(34, 211, 238, 0.2);
box-shadow: 0 0 15px rgba(34, 211, 238, 0.4);
z-index: 2;
pointer-events: none;
}

.darma-loader-uiverse-reactor-core-grid__middle {
width: 100px;
height: 100px;
z-index: 20;
animation: darma-loader-uiverse-reactor-core-grid-spin 8s linear infinite reverse;
}

.darma-loader-uiverse-reactor-core-grid__middle::after {
content: "";
position: absolute;
inset: 0;
border-radius: 50%;
border: 1px solid transparent;
border-left-color: rgba(168, 85, 247, 0.8);
border-bottom-color: rgba(168, 85, 247, 0.2);
box-shadow: 0 0 15px rgba(168, 85, 247, 0.4);
z-index: 2;
pointer-events: none;
}

.darma-loader-uiverse-reactor-core-grid__inner {
width: 60px;
height: 60px;
z-index: 30;
animation: darma-loader-uiverse-reactor-core-grid-spin 4s linear infinite;
background: radial-gradient(
circle,
rgba(255, 255, 255, 0.05) 0%,
transparent 60%
);
}

.darma-loader-uiverse-reactor-core-grid__inner::before {
border: 1px dashed rgba(255, 255, 255, 0.3);
}

.darma-loader-uiverse-reactor-core-grid__item {
position: absolute;
top: 50%;
left: 50%;
transform-origin: 0 0;
z-index: 5;
}

.darma-loader-uiverse-reactor-core-grid__symbol {
display: block;
color: #fff;
font-size: 1.2rem;
font-weight: 400;
text-shadow: 0 0 8px rgba(255, 255, 255, 0.5);
}

.darma-loader-uiverse-reactor-core-grid__outer .darma-loader-uiverse-reactor-core-grid__item-1 {
transform: rotate(0deg) translate(0, -70px);
}

.darma-loader-uiverse-reactor-core-grid__outer .darma-loader-uiverse-reactor-core-grid__item-2 {
transform: rotate(120deg) translate(0, -70px);
}

.darma-loader-uiverse-reactor-core-grid__outer .darma-loader-uiverse-reactor-core-grid__item-3 {
transform: rotate(240deg) translate(0, -70px);
}

.darma-loader-uiverse-reactor-core-grid__middle .darma-loader-uiverse-reactor-core-grid__item-1 {
transform: rotate(0deg) translate(0, -50px);
}

.darma-loader-uiverse-reactor-core-grid__middle .darma-loader-uiverse-reactor-core-grid__item-2 {
